create table store (id uuid primary key, created_at timestamptz not null, name varchar(255) not null unique, type varchar(50) not null, location varchar(255) not null, manager_id uuid);
create table app_users (id uuid primary key, created_at timestamptz not null, full_name varchar(255) not null, email varchar(255) not null unique, password_hash varchar(255) not null, role varchar(80) not null, assigned_store_id uuid references store(id), active boolean not null, force_password_change boolean not null, failed_login_attempts int not null, locked boolean not null, created_by_id uuid, last_login timestamptz);
alter table store add constraint fk_store_manager foreign key (manager_id) references app_users(id);
alter table app_users add constraint fk_user_creator foreign key (created_by_id) references app_users(id);
create table item (id uuid primary key, created_at timestamptz not null, code varchar(255) not null unique, name varchar(255) not null, description varchar(1000), unit_of_measure varchar(255) not null, category varchar(80) not null, reorder_threshold numeric(19,4) not null, active boolean not null);
create table project (id uuid primary key, created_at timestamptz not null, code varchar(255) not null unique, name varchar(255) not null, site_store_id uuid not null references store(id), budget_ceiling numeric(19,4), active boolean not null);
create table store_inventory (id uuid primary key, created_at timestamptz not null, store_id uuid not null references store(id), item_id uuid not null references item(id), quantity_on_hand numeric(19,4) not null, quantity_in_transit numeric(19,4) not null, quantity_frozen numeric(19,4) not null, last_updated timestamptz not null, unique(store_id,item_id));
create table audit_log (id uuid primary key, entity_type varchar(255) not null, entity_id varchar(255) not null, action varchar(255) not null, old_state text, new_state text, performed_by varchar(255) not null, performed_at timestamptz not null);
